void tvsub(struct timeval *t1, struct timeval *t2, struct timeval *result) {
    result->tv_sec = t1->tv_sec - t2->tv_sec;
    result->tv_usec = t1->tv_usec - t2->tv_usec;
    if (result->tv_usec < 0) {
        result->tv_sec--;
        result->tv_usec += 1000000;
    }
}

int parseCommandline(int argc, char *argv[], char* filename,
                     int *q, int *v, int *t, int *p, int *d, int *size){
    int i;
    if (argc < 2) return 1; 
    char flag;

    for(i=1;i<argc;i++) {
      if (argv[i][0]=='-') {
        flag = argv[i][1];
          switch (flag) {
            case 's': 
              i++;
              *size = atoi(argv[i]);
	      printf("Create matrix internally in parse, size = %d \n", *size);
              break;
            case 'f': 
              i++;
	      strncpy(filename,argv[i],100);
	      printf("Read file from %s \n", filename);
              break;
            case 'h': 
              return 1;
              break;
            case 'q': 
              *q = 1;
              break;
			case 'v': 
			  *v = 1;
			  break;
            case 't': 
              *t = 1;
              break;
            case 'p': 
              i++;
              *p = atoi(argv[i]);
              break;
            case 'd': 
              i++;
              *d = atoi(argv[i]);
              break;
        }
      }
    }
    if ((*d >= 0 && *p<0) || (*p>=0 && *d<0)) 
      return 1;
    return 0;
}

